noncompliant:
void function(const int* ptr) {
    int* non_const_ptr = const_cast<int*>(ptr); // Noncompliant: removing const qualification
    *non_const_ptr = 42;
}

void volatile_example(volatile int* ptr) {
    int* non_volatile_ptr = const_cast<int*>(ptr); // Noncompliant: removing volatile qualification
}

compliant:
void function(const int* ptr) {
    // Read from const pointer - no casting needed
    int value = *ptr;
    std::cout << value << std::endl;
}

void function_mutable(int* ptr) {
    *ptr = 42; // Compliant: already non-const pointer
}

// If modification is necessary, pass non-const parameter
void modify_value(int& value) {
    value = 100; // Compliant: parameter is not const
}
